const binary = $input.first().binary || {};

function read(key, fallback) {
  const b = binary[key];
  if (b && b.data) return Buffer.from(b.data, 'base64').toString('utf-8').trim();
  return fallback || '';
}

const appName      = read('appName',  '錢錢管家');
const appVersion   = read('appVersion', '?');
const category     = read('category',  'General');
const message      = read('message',   '');
const contactEmail = read('contactEmail', '');
const platform     = read('platform',  '');
const osVersion    = read('osVersion', '');
const deviceModel  = read('deviceModel', '');
const sourcePage   = read('sourcePage', '');
const hasImages    = read('hasImages', 'false');
const createdAt    = read('createdAt', new Date().toISOString());

const subject = `[${appName} Feedback] ${category} — v${appVersion}`;
const safeMsg = message.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const html = `<div style="font-family:sans-serif;max-width:600px">
  <h2 style="color:#C59B63;border-bottom:2px solid #C59B63;padding-bottom:8px">📱 ${appName} — User Feedback</h2>
  <table cellpadding="10" cellspacing="0" style="width:100%;border-collapse:collapse">
    <tr style="background:#f0f0f0"><th align="left" style="width:130px">欄位</th><th align="left">內容</th></tr>
    <tr style="border-bottom:1px solid #eee"><td><b>類別</b></td><td>${category}</td></tr>
    <tr style="border-bottom:1px solid #eee;background:#fafafa"><td><b>訊息</b></td><td style="white-space:pre-wrap">${safeMsg}</td></tr>
    <tr style="border-bottom:1px solid #eee"><td><b>聯絡信箱</b></td><td>${contactEmail || '未提供'}</td></tr>
    <tr style="border-bottom:1px solid #eee;background:#fafafa"><td><b>App 版本</b></td><td>${appName} v${appVersion}</td></tr>
    <tr style="border-bottom:1px solid #eee"><td><b>平台</b></td><td>${platform} ${osVersion}</td></tr>
    <tr style="border-bottom:1px solid #eee;background:#fafafa"><td><b>裝置</b></td><td>${deviceModel}</td></tr>
    <tr style="border-bottom:1px solid #eee"><td><b>來源頁面</b></td><td>${sourcePage}</td></tr>
    <tr style="border-bottom:1px solid #eee;background:#fafafa"><td><b>附圖</b></td><td>${hasImages === 'true' ? '✅ 是' : '❌ 否'}</td></tr>
    <tr><td><b>提交時間</b></td><td>${createdAt}</td></tr>
  </table>
</div>`;

return [{ json: { emailSubject: subject, emailHtml: html } }];
